package com.korit.clovapi.domain.plan;
import com.jayway.jsonpath.JsonPath; import com.korit.clovapi.global.security.jwt.JwtTokenProvider; import com.korit.clovapi.support.IntegrationTestSupport; import org.junit.jupiter.api.AfterEach; import org.junit.jupiter.api.BeforeEach; import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.http.MediaType; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.test.web.servlet.MockMvc; import java.util.*; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
class PlanIntegrationTest extends IntegrationTestSupport { @Autowired MockMvc mvc; @Autowired JdbcTemplate db; @Autowired JwtTokenProvider jwt; long user,room,plan;
@BeforeEach void setup(){String x=UUID.randomUUID().toString();db.update("INSERT INTO users(email,nickname,personal_invite_code) VALUES(?,?,?)","plan-"+x+"@test","Plan","CLV-"+x.substring(0,6));user=db.queryForObject("SELECT id FROM users WHERE email=?",Long.class,"plan-"+x+"@test");db.update("INSERT INTO friendship_rooms(name) VALUES('Plan test')");room=db.queryForObject("SELECT id FROM friendship_rooms ORDER BY id DESC LIMIT 1",Long.class);db.update("INSERT INTO room_members(room_id,user_id) VALUES(?,?)",room,user);}
@AfterEach void clean(){if(plan!=0){db.update("DELETE FROM plan_stage_photos WHERE plan_id=?",plan);db.update("DELETE FROM plan_checklists WHERE plan_id=?",plan);db.update("DELETE FROM plans WHERE id=?",plan);}db.update("DELETE FROM room_members WHERE room_id=?",room);db.update("DELETE FROM friendship_rooms WHERE id=?",room);db.update("DELETE FROM users WHERE id=?",user);}
@Test void locksStagesBlocksReuploadAndCompletesMemoryTransition() throws Exception {String body=mvc.perform(post("/api/v1/rooms/{id}/plans",room).header("Authorization",b()).contentType(MediaType.APPLICATION_JSON).content("{\"title\":\"Trip\"}")).andExpect(status().isCreated()).andReturn().getResponse().getContentAsString();plan=Long.parseLong(JsonPath.read(body,"$.data.id"));mvc.perform(post("/api/v1/plans/{id}/stage-photos/presign",plan).header("Authorization",b()).contentType(MediaType.APPLICATION_JSON).content("{\"stage\":\"SCHEDULING\",\"contentType\":\"image/jpeg\"}")).andExpect(status().isLocked()).andExpect(jsonPath("$.error.code").value("STAGE_LOCKED"));mvc.perform(post("/api/v1/plans/{id}/stage-photos",plan).header("Authorization",b()).contentType(MediaType.APPLICATION_JSON).content("{\"stage\":\"PROPOSAL\",\"imageUrl\":\"https://test/p.jpg\"}")).andExpect(status().isOk());mvc.perform(post("/api/v1/plans/{id}/stage-photos",plan).header("Authorization",b()).contentType(MediaType.APPLICATION_JSON).content("{\"stage\":\"PROPOSAL\",\"imageUrl\":\"https://test/p2.jpg\"}")).andExpect(status().isConflict()).andExpect(jsonPath("$.error.code").value("STAGE_ALREADY_UPLOADED"));mvc.perform(post("/api/v1/plans/{id}/complete",plan).header("Authorization",b())).andExpect(status().isOk()).andExpect(jsonPath("$.data.status").value("COMPLETED")).andExpect(jsonPath("$.data.memoryStatus").value("CANDIDATE"));}
private String b(){return "Bearer "+jwt.createAccessToken(user);} }
